{
    if (reader.noMore()) {
        reader.fail();
        return false;
    }
    {
        size_t _csize;
        yarp::os::idl::WireState _etype;
        reader.readListBegin(_etype, _csize);
        // WireReader removes BOTTLE_TAG_LIST from the tag
        constexpr int expected_tag = ((BOTTLE_TAG_INT32) & (~BOTTLE_TAG_LIST));
        if constexpr (expected_tag != 0) {
            if (_csize != 0 && _etype.code != expected_tag) {
                return false;
            }
        }
        joints.resize(_csize);
        if (_csize != 0 && !reader.readBlock(reinterpret_cast<char*>(joints.data()), joints.size() * sizeof(std::int32_t))) {
            return false;
        }
        reader.readListEnd();
    }
    if (!reader.noMore()) {
        reader.fail();
        return false;
    }
    return true;
}

